186	  display: "flex",
187	  flexWrap: "wrap",
188	  alignItems: "center",
189	  gap: "var(--space-sm)",
190	};
191	
192	const commentAuthorStyle: React.CSSProperties = {
193	  fontSize: "0.85rem",
194	  fontWeight: 600,
195	};
196	
197	const commentMetaStyle: React.CSSProperties = {
198	  color: "var(--color-text-muted)",
199	  fontSize: "0.75rem",
200	};
201	
202	const commentBodyStyle: React.CSSProperties = {
203	  margin: 0,
204	  whiteSpace: "pre-wrap",
205	  lineHeight: 1.5,
206	  fontSize: "0.9rem",
207	};
208	
209	const composerStyle: React.CSSProperties = {
210	  display: "grid",
211	  gap: "var(--space-sm)",
212	  paddingTop: "var(--space-xs)",
213	  borderTop: "1px solid var(--color-border)",
214	};
215	
216	const labelStyle: React.CSSProperties = {
217	  fontSize: "0.85rem",
218	  fontWeight: 600,
219	};
220	
221	const textareaStyle: React.CSSProperties = {
222	  width: "100%",
223	  padding: "10px 12px",
224	  borderRadius: "var(--radius-sm)",
225	  border: "1px solid var(--color-border)",
226	  background: "var(--color-bg)",
227	  color: "var(--color-text)",
228	  fontSize: "0.9rem",
229	  fontFamily: "inherit",
230	  resize: "vertical",
231	};
232	
233	const composerFooterStyle: React.CSSProperties = {
234	  display: "flex",
235	  justifyContent: "space-between",
236	  alignItems: "center",
237	  gap: "var(--space-sm)",
238	  flexWrap: "wrap",
239	};
